# Shapes module: interfaces and abstract classes
from types import Color

interface IShape:
    def area(self) -> float
    def perimeter(self) -> float

interface IDrawable:
    def draw(self) -> str

@abstract
class Shape(IShape, IDrawable):
    color: Color
    name: str

    def __init__(self, name: str, color: Color):
        self.name = name
        self.color = color

    def description(self) -> str:
        return f"{self.name} (color: {self.color.name})"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__("Rectangle", color)
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    @virtual
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Drawing rectangle {self.width} x {self.height}"

class Circle(Shape):
    radius: float

    def __init__(self, radius: float, color: Color):
        super().__init__("Circle", color)
        self.radius = radius

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @virtual
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def draw(self) -> str:
        return f"Drawing circle r={self.radius}"

