# Utils module: helper functions and classes
from shapes import Rectangle
from types import Point, Dimension

def calculate_average(values: list[float]) -> float:
    total: float = 0.0
    for v in values:
        total += v
    return total / float(len(values))

def find_max(values: list[float]) -> float:
    current_max: float = values[0]
    for v in values:
        if v > current_max:
            current_max = v
    return current_max

class Counter:
    @static
    _count: int = 0

    def __init__(self):
        Counter._count += 1

    def get_id(self) -> int:
        return Counter._count

    @staticmethod
    def total_count() -> int:
        return Counter._count

from types import Status

class Task:
    name: str
    status: Status

    def __init__(self, name: str):
        self.name = name
        self.status = Status.PENDING

    def complete(self):
        self.status = Status.COMPLETED

    def get_info(self) -> str:
        return f"{self.name}: {self.status.name}"
